-- {"operators": "OUTER_JOIN,AGGREGATE,DISTINCT", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,OORDER,NEW_ORDER", "ducklake": true}
SELECT w.W_ID, d.D_ID, COUNT(DISTINCT c.C_ID) AS custs, COUNT(DISTINCT o.O_ID) AS orders, COUNT(DISTINCT no.NO_O_ID) AS new_orders FROM dl.WAREHOUSE w JOIN dl.DISTRICT d ON w.W_ID = d.D_W_ID JOIN dl.CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID LEFT JOIN dl.NEW_ORDER no ON o.O_W_ID = no.NO_W_ID AND o.O_D_ID = no.NO_D_ID AND o.O_ID = no.NO_O_ID GROUP BY w.W_ID, d.D_ID;
